Javascript.logic:
var bailiffId = Services.getValue(this.dataBinding);
if(BailiffId.validate() == null) {
	if(bailiffId != "%") {
		var currentlyOwnedBy = Services.getValue(OwningCourt_Code.dataBinding);
		checkBailiffIdExists(currentlyOwnedBy, bailiffId);
	}
	else {
		Services.setValue(_bailiffIdExistsXPath, "true");
	}
}

Javascript.validate:
var value = Services.getValue(this.dataBinding);
var errCode = null;
if (value == "%")
{
	return null;
}
if (!CaseManUtils.isBlank(value)) 
{
	errCode = CaseManValidationHelper.validatePattern(value, CaseManValidationHelper.NUMERIC_PATTERN, "CaseMan_NotNumericValue_Msg");
}
if (value == "99")
{
	errCode = ErrorCode.getErrorCode("CaseMan_BailiffCannotBe99_Msg");
}
return errCode;

Javascript.miscCode:
var _bailiffIdExistsXPath = "/ds/var/page/OracleReportForm/BailiffIdExists";

Status_RunReportButton.validationList = ["BailiffId", "Params_StartDate_Txt", "Params_EndDate_Txt"];

function checkBailiffIdExists(currentlyOwnedBy, bailiffId)
{
	var params = new ServiceParams();
	params.addSimpleParameter("currentlyOwnedBy", currentlyOwnedBy);
	params.addSimpleParameter("bailiffId", bailiffId);
	Services.callService("checkBailiffIdExists", params, checkBailiffIdExists, true);
}
checkBailiffIdExists.onSuccess = function(dom)
{
	if(dom != null) {
		var results = dom.selectSingleNode("/BailiffFound");
		if(results != null) {
			if(XML.getNodeTextContent(results) == 0) {
				Services.setValue(_bailiffIdExistsXPath, "false");
				alert("No Warrants Identified For Bailiff " + Services.getValue(BailiffId.dataBinding) + ",\nPlease Enter Another Bailiff");
			}
			else {
				Services.setValue(_bailiffIdExistsXPath, "true");
			}
		}
		else {
			this.onError();
		}
	}
	else {
		this.onError();
	}
}
checkBailiffIdExists.onError = function()
{
	alert("Error querying database to check Bailiff ID");
}

Status_RunReportButton.enableOn = [_bailiffIdExistsXPath];
Status_RunReportButton.isEnabled = function()
{
	if(Services.getValue(_bailiffIdExistsXPath) == "true") {
		return true;
	}
	return false;
}
